**PhysicsSystem.js:**
```javascript
class PhysicsSystem {
  constructor() {
    this.bhTree = new BarnesHutTree();
    this.nodePool = new BHNodePool(10000);
  }

  step(bodies, dt) {
    this.bhTree.build(bodies, this.nodePool);
    for (const body of bodies) {
      const force = this.bhTree.calculateForce(body);
      body.applyForce(force, dt);
    }
  }
}
```

